// Obtém todos os itens de entrada do n8n
const inputData = $input.all().map(item => item.json);

const transformData = (data) => {
  return data.map(item => {
    const transformedItem = { ...item };

    if (item.learning_stage_info) {
      const learningInfo = item.learning_stage_info;

      // Concatena os valores da lista "attribution_windows" com "+"
      if (learningInfo.attribution_windows) {
        transformedItem.learning_attribution_windows = learningInfo.attribution_windows.join("+");
      }

      // Copia os demais valores
      if (learningInfo.conversions !== undefined) {
        transformedItem.learning_conversions = learningInfo.conversions;
      }

      if (learningInfo.last_sig_edit_ts !== undefined) {
        transformedItem.learning_last_sig_edit_ts = learningInfo.last_sig_edit_ts;
      }

      if (learningInfo.status) {
        transformedItem.learning_status = learningInfo.status;
      }

      // Remove a chave original
      delete transformedItem.learning_stage_info;
    }

    return transformedItem;
  });
};

// Transforma os dados
const outputData = transformData(inputData);

// Retorna os dados transformados no formato esperado pelo n8n
return outputData.map(json => ({ json }));

function processItem(item) {
  const requiredFields = [
    "account_id", "campaign_id", "created_time", "start_time", "end_time", "id",
    "name", "billing_event", "budget_remaining", "daily_budget", "destination_type",
    "is_dynamic_creative", "effective_status", "optimization_goal"
  ];

  // Garante a presença de todos os campos obrigatórios
  requiredFields.forEach(field => {
    if (!(field in item.json)) {
      item.json[field] = null;
    }
  });

  // Converte valores undefined para null
  for (const key in item.json) {
    if (item.json[key] === undefined) {
      item.json[key] = null;
    }
  }

  return item;
}

// Processa todos os itens
return $input.all().map(item => processItem(item));

